from typing import TypedDict
from langchain_anthropic import ChatAnthropic
from langgraph.graph import StateGraph, END

MODEL_MAP = {
    "simple": "claude-haiku-4-5-20251001",
    "medium": "claude-sonnet-5",
    "hard":   "claude-opus-4-8",
}

class ModelRouterState(TypedDict):
    query: str
    tier: str
    model_used: str
    response: str

def classify_node(state: ModelRouterState) -> dict:
    result = classifier.invoke([
        {"role": "system", "content": ROUTING_SYSTEM},
        {"role": "user", "content": state["query"]},
    ])
    return {"tier": result.tier}

def route_edge(state: ModelRouterState) -> str:
    return state["tier"]

def make_handler(tier: str):
    model_id = MODEL_MAP[tier]
    llm = ChatAnthropic(model=model_id)

    def handler(state: ModelRouterState) -> dict:
        response = llm.invoke(state["query"])
        return {"response": response.content, "model_used": model_id}

    handler.__name__ = f"handle_{tier}"
    return handler

builder = StateGraph(ModelRouterState)
builder.add_node("classify", classify_node)
for tier in MODEL_MAP:
    builder.add_node(f"handle_{tier}", make_handler(tier))
    builder.add_edge(f"handle_{tier}", END)

builder.set_entry_point("classify")
builder.add_conditional_edges("classify", route_edge, {
    tier: f"handle_{tier}" for tier in MODEL_MAP
})

graph = builder.compile()

def rule_based_tier(query: str, has_attachment: bool = False) -> str:
    tokens = len(query.split())

    if has_attachment:
        return "hard"       # vision or long-context tasks always need full model
    if tokens < 30 and "?" in query:
        return "simple"     # short questions
    if tokens > 400:
        return "hard"       # long inputs typically need higher quality
    if any(kw in query.lower() for kw in ["code", "implement", "debug", "architecture"]):
        return "medium"
    return "simple"

# Mix rules and LLM: use rules first, fall back to LLM classifier only when ambiguous
def hybrid_tier(query: str, has_attachment: bool = False) -> str:
    rule_result = rule_based_tier(query, has_attachment)
    tokens = len(query.split())

    # Only call the LLM classifier for the ambiguous middle range
    if 30 <= tokens <= 400 and not has_attachment:
        result = classifier.invoke([
            {"role": "system", "content": ROUTING_SYSTEM},
            {"role": "user", "content": query},
        ])
        return result.tier

    return rule_result

# Approximate input token costs in USD per million tokens (as of 2025)
COST_PER_MTok = {
    "claude-haiku-4-5-20251001": 0.80,
    "claude-sonnet-5":           3.00,
    "claude-opus-4-8":          15.00,
}

def estimate_cost(model_id: str, prompt_tokens: int, completion_tokens: int) -> float:
    rate = COST_PER_MTok.get(model_id, 3.00)
    # Simplified: treat all tokens at the same rate
    return (prompt_tokens + completion_tokens) / 1_000_000 * rate

# Add cost tracking to the handler
def make_handler(tier: str):
    model_id = MODEL_MAP[tier]
    llm = ChatAnthropic(model=model_id)

    def handler(state: ModelRouterState) -> dict:
        response = llm.invoke(state["query"])
        usage = response.usage_metadata or {}
        cost = estimate_cost(
            model_id,
            usage.get("input_tokens", 0),
            usage.get("output_tokens", 0),
        )
        return {
            "response": response.content,
            "model_used": model_id,
            "estimated_cost_usd": cost,
        }

    return handler

class EscalatingState(ModelRouterState):
    escalated: bool

def handle_simple_with_escalation(state: EscalatingState) -> dict:
    llm = ChatAnthropic(model=MODEL_MAP["simple"])

    class SimpleResponse(BaseModel):
        answer: str
        confident: bool  # model self-reports confidence

    response = llm.with_structured_output(SimpleResponse).invoke(state["query"])

    if not response.confident:
        # Escalate: re-run with medium model
        medium_llm = ChatAnthropic(model=MODEL_MAP["medium"])
        escalated_response = medium_llm.invoke(state["query"])
        return {
            "response": escalated_response.content,
            "model_used": MODEL_MAP["medium"],
            "escalated": True,
        }

    return {
        "response": response.answer,
        "model_used": MODEL_MAP["simple"],
        "escalated": False,
    }

from dataclasses import dataclass, field
from langchain_core.messages import BaseMessage

@dataclass
class RequestProfile:
    has_image: bool = False
    has_code_block: bool = False
    estimated_tokens: int = 0
    requires_tool_use: bool = False

def profile_request(query: str, attachments: list = None) -> RequestProfile:
    attachments = attachments or []
    return RequestProfile(
        has_image=any(a.get("type") == "image" for a in attachments),
        has_code_block="```" in query or "def " in query or "class " in query,
        estimated_tokens=len(query.split()) * 1.3,  # rough approximation
        requires_tool_use=any(
            kw in query.lower()
            for kw in ["search", "fetch", "calculate", "run", "execute"]
        ),
    )

CAPABILITY_RULES = [
    # (condition, model_id)
    (lambda p: p.has_image,                       "claude-opus-4-8"),
    (lambda p: p.estimated_tokens > 2000,         "claude-opus-4-8"),
    (lambda p: p.has_code_block,                  "claude-sonnet-5"),
    (lambda p: p.requires_tool_use,               "claude-sonnet-5"),
]

def capability_route(profile: RequestProfile) -> str | None:
    for condition, model_id in CAPABILITY_RULES:
        if condition(profile):
            return model_id
    return None  # no capability rule matched; fall through to complexity routing

def route_request(query: str, attachments: list = None) -> str:
    profile = profile_request(query, attachments)
    cap_model = capability_route(profile)
    if cap_model:
        return cap_model
    # Fall through to complexity classifier
    tier = rule_based_tier(query)
    return MODEL_MAP[tier]

class BudgetAwareRouter:
    def __init__(self, daily_budget_usd: float):
        self.daily_budget = daily_budget_usd
        self.spent_today = 0.0

    def route(self, query: str) -> str:
        remaining_fraction = 1.0 - (self.spent_today / self.daily_budget)

        # Tighten routing as budget depletes
        if remaining_fraction < 0.15:
            # Less than 15% budget left — force everything to cheapest model
            return MODEL_MAP["simple"]
        if remaining_fraction < 0.40:
            # Less than 40% — suppress hard tier, cap at medium
            tier = rule_based_tier(query)
            return MODEL_MAP["medium"] if tier == "hard" else MODEL_MAP[tier]

        # Normal routing
        tier = rule_based_tier(query)
        return MODEL_MAP[tier]

    def record_spend(self, cost_usd: float):
        self.spent_today += cost_usd

router = BudgetAwareRouter(daily_budget_usd=100.0)
